## 算法描述
> 线段树常用于解决区间修改查询问题，包括但不限于最大值、最小值和求和。线段树最大的难点，就是你不知道它将用来解决怎样的问题。

### 定义
线段树就是一棵普普通通的树，它的大部分节点都有两个子节点，但并不是一棵满二叉树，也不是完全二叉树。这一点你在学习后面的文章后就会明白了。
线段树上每一个节点都代表着一段区间，而每个子结点代表的区间长度都是其父节点的一半。若长度是奇数则会有些许偏差。而节点的值则是这个区间的需求。
### 应用
线段树可以解决大部分的区间问题，只要你能想清楚怎么分治，基本上就是线段树没得跑。哪怕这个区间的需求是连续的。
通常来说，线段树的操作分为以下几种：
- **建树**：输入数组并建立对应需求的线段树
- **单点修改**：将 $x$ 位置的元素改成 $v$
- **区间修改**：将 $l$ 到 $r$ 位置的所用元素改成或增加 $v$
- **区间查询**：查询 $l$ 到 $r$ 区间内的最大/最小/和/其他需求

## 算法实现
线段树用数组实现。注意数组大小要开到 $4 \times n$。左右子树的编号分别是 $i \times 2$ 和 $i \times 2 + 1$。
```cpp
ll lc(ll p){return p << 1;}
ll rc(ll p){return p << 1 | 1;}
```
### 初始化
从根节点开始，不断的分割区间直到该区间只剩单个数，然后开始向上汇总。传入两个变量 `l` 和 `r`， 表示当前节点表示的线段。
```cpp
void pushUp(ll p){
	sum[p] = sum[lc(p)] + sum[rc(p)];
}

void build(ll p, ll l, ll r){
	if(l == r){
		sum[p] = a[l];
		return;
	}
	ll mid = (l + r) >> 1;
	build(lc(p), l, mid);
	build(rc(p), mid + 1, r);
	pushUp(p); 
}
```
### 区间查询
从根节点开始，如果当前的线段不被查询的区间完全包含就一直分两段尝试，直到它被完全包含了，返回该线段的值然后继续递归其他的。
```cpp
ll Query(ll p, ll l, ll r, ll ql, ll qr){
	if(ql <= l && qr >= r){
		return sum[p];
	}
	pushDown(p, l, r);
	ll mid = (l + r) >> 1, ans = 0;
	if(ql <= mid){
		ans += Query(lc(p), l, mid, ql, qr);
	}
	if(qr > mid){
		ans += Query(rc(p), mid + 1, r, ql, qr);
	}
	return ans;
}
```
### 区间修改
如果每次修改都从上到下全改一遍，复杂度得 $\mathcal{O}(n)$ ，太浪费时间了，完全体现不出线段树的优势所在。因此引入懒标记（Lazy Tag）。和查询一样，当线段被区间完全覆盖时，对应的节点自己更新，但它的孩子们不更新。这时给他安上一个懒标记，表示它的子节点需要更新的大小。当区间没有完全覆盖，需要拆分的时候，将当前变量的标记拆掉，传给子节点，这样才不会错算。
```cpp
void Update(ll p, ll l, ll r, ll ql, ll qr, ll d){
	if(ql <= l && qr >= r){
		sum[p] += d * (r - l + 1);
		tag[p] += d;
		return;
	}
	pushDown(p, l, r);
	ll mid = (l + r) >> 1;
	if(ql <= mid){
		Update(lc(p), l, mid, ql, qr, d);
	}
	if(qr > mid){
		Update(rc(p), mid + 1, r, ql, qr, d);
	}
	pushUp(p);
}
```
### 例题
**例题**：Luogu P3372
```cpp
#include <iostream>
#include <algorithm>
using namespace std;
typedef long long ll;
const int MAXN = 1e5 + 5;
ll segt[4 * MAXN], tag[4 * MAXN], a[MAXN];
ll lc(ll p){return p << 1;}
ll rc(ll p){return p << 1 | 1;}
void pushUp(ll p){
    segt[p] = min(segt[lc(p)], segt[rc(p)]);
}
void build(ll p, ll l, ll r){
    if(l == r){
        segt[p] = a[l];
        return;
    }
    ll mid = (l + r) >> 1;
    build(lc(p), l, mid);
    build(rc(p), mid + 1, r);
    pushUp(p);
}
void moveTag(ll p, ll k){
    tag[p] += k;
    segt[p] += k;
}
void pushDown(ll p){
    moveTag(lc(p), tag[p]);
    moveTag(rc(p), tag[p]);
    tag[p] = 0;
}
void Update(ll p, ll l, ll r, ll ql, ll qr){
    if(ql <= l && qr >= r){
        moveTag(p, 1);
        return;
    }
    pushDown(p);
    ll mid = (l + r) >> 1;
    if(ql <= mid)Update(lc(p), l, mid, ql, qr);
    if(qr > mid)Update(rc(p), mid + 1, r, ql, qr);
    pushUp(p);
}
ll Query(ll p, ll l, ll r, ll ql, ll qr){
    if(ql <= l && qr >= r){
        return segt[p];
    }
    pushDown(p);
    ll mid = (l + r) >> 1, ans = 2147483647;
    if(ql <= mid)ans = min(ans, Query(lc(p), l, mid, ql, qr));
    if(qr > mid)ans = min(ans, Query(rc(p), mid + 1, r, ql, qr));
    return ans;
}
int main(){
    ll n, m;
    cin >> n >> m;
    for(ll i = 1; i <= n; i ++){
        cin >> a[i];
    }
    build(1, 1, n);
    while(m --){
        ll opt, l, r;
        cin >> opt >> l >> r;
        if(opt == 1){
            Update(1, 1, n, l, r);
        }else{
            cout << Query(1, 1, n, l, r) << "\n";
        }
    }
    return 0;
}
```

## 变种
### 区间和并
在遇到有区间连续的需求时，我们发现传统线段树并不适用，因为分段时无法控制答案的范围，在向上整理回父节点时可能会遇到答案的中间部分没有连接但却错误转移的情况。
我们可以定义额外的变量存于线段树的数组，分别表示了以区间最左边和最右边起始的答案，这样就只需要思考如何 `pushUp` 转移了。
### 例题
**例题**：区间最大连续子序列和
输入一个长度为 $n$ 的数组 $a$，数组的元素均为整数且满足 $-4000 \leq a_i \leq 4000$。对该数组可以发出 $m$ 条指令。指令共有 $2$ 种：
- `1 x v`，该指令将 $a_x$ 的值修改为 $v$
- `2 l r`，该指令查询区间 $l$ 到 $r$ 的最大连续子序列和，即区间所有可能的连续子序列中求和的最大值

```cpp
#include <iostream>
#include <algorithm>
#include <climits>
using namespace std;
typedef long long ll;
const ll MAXN = 400005, fINF = LONG_LONG_MIN;
struct Node{
    ll sum = 0, lans = fINF, rans = fINF, ans = fINF;
}segt[4 * MAXN];
ll a[MAXN];
ll lc(ll p){return p << 1;}
ll rc(ll p){return p << 1 | 1;}
void pushUp(ll p){
    segt[p].sum = segt[lc(p)].sum + segt[rc(p)].sum;
    segt[p].lans = max({segt[lc(p)].sum + segt[rc(p)].lans, segt[lc(p)].lans});
    segt[p].rans = max({segt[rc(p)].sum + segt[lc(p)].rans, segt[rc(p)].rans});
    segt[p].ans = max({segt[lc(p)].rans + segt[rc(p)].lans, segt[lc(p)].ans, segt[rc(p)].ans});
}
void build(ll p, ll l, ll r){
    if(l == r){
        segt[p].ans = segt[p].lans = segt[p].rans = segt[p].sum = a[l];
        return;
    }
    ll mid = (l + r) >> 1;
    build(lc(p), l, mid);
    build(rc(p), mid + 1, r);
    pushUp(p);
}
void Update(ll p, ll l, ll r, ll x, ll v){
    if(l == r){
        segt[p].sum = segt[p].ans = segt[p].lans = segt[p].rans = v;
        return;
    }
    ll mid = (l + r) >> 1;
    if(x <= mid)Update(lc(p), l, mid, x, v);
    else if(x > mid)Update(rc(p), mid + 1, r, x, v);
    pushUp(p);
}
Node Query(ll p, ll l, ll r, ll ql, ll qr){
    if(ql <= l && qr >= r){
        return segt[p];
    }
    ll mid = (l + r) >> 1;
    if(ql <= mid && qr > mid){
        Node ans, qla = Query(lc(p), l, mid, ql, qr), qra = Query(rc(p), mid + 1, r, ql, qr);
        ans.sum = qla.sum + qra.sum;
        ans.ans = max({ans.ans, qla.ans, qra.ans, qla.rans + qra.lans});
        ans.lans = max({ans.lans, qla.lans, qla.sum + qra.lans});
        ans.rans = max({ans.rans, qra.rans, qra.sum + qla.rans});
        return ans;
    }else if(ql <= mid){
        return Query(lc(p), l, mid, ql, qr);
    }else{
        return Query(rc(p), mid + 1, r, ql, qr);
    }
}
int main(){
    ll n, m;
    cin >> n >> m;
    for(ll i = 1; i <= n; i ++){
        cin >> a[i];
    }
    build(1, 1, n);
    while(m --){
        ll opt, l, r;
        cin >> opt >> l >> r;
        if(opt == 1){
            Update(1, 1, n, l, r);
        }else{
            cout << Query(1, 1, n, l, r).ans << "\n";
        }
    }
    return 0;
}
```

## 总结
极为常用，需要会用、会推、会写且达到熟练的地步。复杂度 $\mathcal{O(log_2 n)}$，已经很快了。

# 算法描述
> 恐龙，是指三角龙、现代鸟类和梁龙的最近共同祖先 (LCA) 及其所有后代。  ——百度百科

假设有一棵树，上面有两个节点，求两个节点最近的共同祖先节点。也可以理解为包含这两个节点的子树是从什么时候分开的。
# 算法思路
> 一生二，二生四，四生万物。  ——泥土笨笨

采用倍增的思想，将查询最近共同祖先问题分成若干部：
## 预处理
预处理一个数组 `anc[i][j]` 表示 $i$ 节点的 $2^j$ 号祖先的编号。其中有 `anc[i][j] = anc[anc[i][j - 1]][j - 1];` 意思是 $i$ 的 $2^j$ 祖先就是 $i$ 的 $2^{j-1}$ 的祖先的 $2^{j-1}$ 祖先。通过这个式子就可以转移了。
转移过程中同时预处理 $dep[i]$ 数组表示深度，后面会用到。
```cpp
void dfs(ll u, ll father){ //该节点和它的父亲节点
	dep[u] = dep[father] + 1; //预处理深度
	anc[u][0] = father; //i 的 第一个祖先，即父亲。
	for(ll i = 1; (1 << i) <= dep[u]; i ++){
		anc[u][i] = anc[anc[u][i - 1]][i - 1]; //转移，由于是从小到大枚举的j，所以当前的anc转移一定是正确的
	}
	for(ll i = head[u]; i; i = pool[i].next){ //往下递归
		if(pool[i].v != father){
			dfs(pool[i].v, u);
		}
	}
}
```
## 调整深度
追平深度。顾名思义，通过不断调整深度让需要查询的两个节点深度相等。
```cpp
if(dep[x] < dep[y]){
	swap(x, y);
}
while(dep[x] > dep[y]){
	x = anc[x][lg[dep[x] - dep[y]] - 1];
}
```
## 跳跃结算
一起往上调，跳的步数从 $2^{dep_x}$ 步开始不断尝试，如果调完了发现重合，就放弃，然后尝试少跳一点，以此类推。直到最后到达了最接近共同祖先的位置，即共同祖先的孩子节点。为什么重合要放弃？因为谁也没办法保证当前的重合点是最近的，要不断尝试下调就太麻烦了。
```cpp
if(x == y)return x;
for(ll i = lg[dep[x]]; i >= 0; i --){
	if(anc[x][i] != anc[y][i]){
		x = anc[x][i];
		y = anc[y][i];
	}
}
return anc[x][0];
```
# 总代码
例题：[洛谷 P3379 【模板】 最近公共祖先（LCA）](https://www.luogu.com.cn/problem/P3379)
```cpp
#include <iostream>
#include <algorithm>
#include <cmath>
using namespace std;
typedef long long ll;
const ll MAXN = 500005;
struct Node{
	ll v, next;
}pool[2 * MAXN];
ll anc[MAXN][25], dep[MAXN], head[MAXN], nn, lg[MAXN];
ll n, m, s;

void addEdge(ll u, ll v){
	pool[++nn].v = v;
	pool[nn].next = head[u];
	head[u] = nn;
}

void dfs(ll u, ll father){
	dep[u] = dep[father] + 1;
	anc[u][0] = father;
	for(ll i = 1; (1 << i) <= dep[u]; i ++){
		anc[u][i] = anc[anc[u][i - 1]][i - 1];
	}
	for(ll i = head[u]; i; i = pool[i].next){
		if(pool[i].v != father){
			dfs(pool[i].v, u);
		}
	}
}

ll lca(ll x, ll y){
	if(dep[x] < dep[y]){
		swap(x, y);
	}
	while(dep[x] > dep[y]){
		x = anc[x][lg[dep[x] - dep[y]] - 1];
	}
	if(x == y)return x;
	for(ll i = lg[dep[x]]; i >= 0; i --){
		if(anc[x][i] != anc[y][i]){
			x = anc[x][i];
			y = anc[y][i];
		}
	}
	return anc[x][0];
}

int main(){
	cin >> n >> m >> s;
	for(ll i = 1; i <= n - 1; i ++){
		ll x, y;
		cin >> x >> y;
		addEdge(x, y);
		addEdge(y, x);
	}
	for(ll i = 1; i <= n; i ++){
		lg[i] = lg[i - 1] + ((1 << lg[i - 1]) == i);
	}
	dfs(s, 0);
	for(ll i = 1; i <= m; i ++){
		ll x, y;
		cin >> x >> y;
		cout << lca(x, y) << "\n";
	}
	return 0;
}
```

# 问题叙述
> RMQ 是 Range Maximum/Minimum Query 的缩写，表示可重复贡献的区间最大/最小值。

显而易见的，可以用线段树实现。但是由于该问题不涉及修改操作，且线段树太长了不好写，十分浪费时间。

这是就需要用到好理解又好写的ST表了。
# 算法思路
> ST表(Sparse Table)是用于解决**可重复贡献问题**的数据结构。

**倍增思想**：我们考虑将 $st_{i,j}$ 定义为 起点为 $i$, 到 $i + 2^j - 1$ 位置的所有元素的最大值。例如 $st_{i,1}$ 表示 $i$ 和 $i + 1$ 中的最大值。
## 转移过程
把当前区间拆成两个大小相等的区间，用动态规划求出答案。
$$st_{i,j} = max(st_{i,j - 1},st_{i + 2^{j-1},j - 1})$$
这样就可以保证该区间内所有的元素都被转移了。预处理就是将 $st_{i,0}$ 表示第 $i$ 个元素的最大值，即本身。
## 查询过程
查询过程也一样，分成两个区间，这里我用的是  $st_{i,k}$ 和 $st_{r-2^k+1,k}$，因为这样刚好有一部分重叠，可以保证答案转移的正确性，然后分别求最大值最后在汇总一下。
$$max(st_{l,k}, st_{r - 2^k + 1,k})$$
其中的 `k = log[r - l + 1]`，用于分隔两个区间。至于怎么求 $\log$，这里我用的是传统求 `lg[i] + 1` 的写法，见下方代码。
# 总代码
**例题：洛谷 [P3865【模板】ST 表 && RMQ 问题](https://www.luogu.com.cn/problem/P3865)**
```cpp
#include <iostream>
#include <algorithm>
#include <queue>
using namespace std;
typedef long long ll;
const ll MAXN = 1e5 + 5;
ll st[MAXN][25], lg[MAXN];

ll Query(ll l, ll r){
	ll k = lg[r - l + 1] - 1;
	return max(st[l][k], st[r - (1 << k) + 1][k]);
}

int main(){
	ios::sync_with_stdio(false);
	cin.tie(0);
	cout.tie(0); 
	ll n, m;
	cin >> n >> m;
	for(ll i = 1; i <= n; i ++){
		cin >> st[i][0];
	}
	for(ll i = 1; i <= n; i ++){
		lg[i] = lg[i - 1] + ((1 << lg[i - 1]) == i);
	}
	for(ll j = 1; j <= 20; j ++){
		for(ll i = 1; i + (1 << j) - 1 <= n; i ++){
			st[i][j] = max(st[i][j - 1], st[i + (1 << (j - 1))][j - 1]);
		}
	}
	while(m --){
		ll l, r;
		cin >> l >> r;
		cout << Query(l, r) << "\n";
	}
	return 0;
}
```

# 更多思考
> 为什么 ST表 似乎很少被用于区间求和之类的问题？

这个问题看起来很傻，却很有用。大概有如下两个原因：
- 可以用前缀和，更好写还不容易错
- ST表如果想要O(1)查询，需要满足所求的问题区间能够重复覆盖。因为查询是两边重叠算的啊

显然，对于第二点，区间求和并不满足条件（如果重复覆盖就会有许多值被加了多次）。那么可不可以进行二进制拆分呢？答案显然是可以的。

# 算法描述
> 三个破变量，一共就十行。编程十分钟，运行一晚上。

很多人认为 Floyd 就是简单的动态规划，甚至有人直接把它当模板背了下来，导致不会变通而 WA 了 [P1119](https://www.luogu.com.cn/problem/P1119)。然而其实大多数初学者~~包括我~~一开始都理解错了它，包括原理。
# 算法实现
定义 $dis_{i,j}^k$ 表示只包含前 $k$ 个节点时 $i$ 到 $j$ 的最短路。而加不加入这个 $k$ 号元素前后有什么区别呢？无非就是某两个点的最短路通过 $k$ 号点松弛出了更有的最短路嘛。于是就有了经典代码：
```cpp
void Floyd(){
	for(ll k = 1; k <= n; k ++){
		for(ll i = 1; i <= n; i ++){
			for(ll j = 1; j <= n; j ++){
				dis[i][j] = min(dis[i][j], dis[i][k] + dis[k][j]);
			}
		}
	}
}
```
那么如何初始化呢？如果 $i$ 到 $j$ 有路，就初始化为边长。否则初始化为最大值。
```cpp
for(ll i = 1; i <= n; i ++){
	for(ll j = 1; j <= n; j ++){
		if(i == j)dis[i][j] = 0;
		else if(gph[i][j])dis[i][j] = gph[i][j];
		else dis[i][j] = INF;
	}
}
```
这就完了吗？这值得写博客吗？当然不值。~~虽然我本来就是给自己写来复习的~~
# Floyd应用

## Floyd解决传递闭包问题
[题目传送门](www.luogu.com.cn/problem/B3611)
> 在有向图中，定义 $d_{i,j}$ 如果是 1，则表示 $i$ 能到达 $j$，否则反之。

这该如何解决呢？转换一下定义。
定义 $d_{i,j}^k$ 表示只有前 $k$ 个点时 $i$ 能否到达 $j$。同理，加入了一个元素 $k$ 之后无非就是有一组 $i$ 能通过它到达 $j$ 了。

```cpp
void Floyd(){
	for(ll i = 1; i <= n; i ++){
		for(ll j = 1; j <= n; j ++){
			if(graph[i][j])d[i][j] = 1;
			else d[i][j] = 0;
		}
	}
	for(ll k = 1; k <= n; k ++){
		for(ll i = 1; i <= n; i ++){
			for(ll j = 1; j <= n; j ++){
				d[i][j] = d[i][j] || (d[i][k] && d[k][j]);
			}
		}
	}
	for(ll i = 1; i <= n; i ++){
		for(ll j = 1; j <= n; j ++){
			cout << d[i][j] << " ";
		}
		cout << "\n";
	}
}
```

