## Floyd求最小环
依旧是改定义：$d_{i,j}^k$ 为前 $k$ 个节点中可以确定的最小环的大小。则匹配最短路，可以在算最短路之后算环了，可以理解为以 $k$ 为一个顶点，由 $k$ 可以到达的 $i$ 和 $j$ 以及 $dis_{i,j}$ 也就是最短路构成的环。然后枚举已经算出最短路的 $i,j$ 即可。
例题就是 [P2738 篱笆回路](https://www.luogu.com.cn/problem/P2738)。这题输入特别逆天，所以给了完整代码。
```cpp
#include <iostream>
#include <algorithm>
using namespace std;
typedef long long ll;
const ll MAXN = 305;
const ll INF = 2147483647;

struct Edge{
	ll u, v, w;
	bool lside[MAXN], rside[MAXN];
}edge[MAXN]; 

ll adj[MAXN][MAXN], father[MAXN], m, n, idx[MAXN], dis[MAXN][MAXN];

ll find(ll x){
	if(father[x] == x)return x;
	return father[x] = find(father[x]);
}

void merge(ll x, ll y){
	father[find(x)] = find(y);
}

ll Floyd(){
	ll ans = INF;
	for(ll i = 1; i <= n; i ++){
		for(ll j = 1; j <= n; j ++){
			if(!dis[i][j])dis[i][j] = INF;
			if(!adj[i][j])adj[i][j] = INF;
		}
	}
	for(ll i = 1; i <= n; i ++){
		adj[i][i] = dis[i][i] = 0;
	}
	for(ll k = 1; k <= n; k ++){
		for(ll i = 1; i <= k - 1; i ++){
			for(ll j = i + 1; j <= k - 1; j ++){
				ans = min(ans, adj[i][k] + adj[k][j] + dis[i][j]);
			}
		}
		for(ll i = 1; i <= n; i ++){
			for(ll j = 1; j <= n; j ++){
				dis[i][j] = min(dis[i][j], dis[i][k] + dis[k][j]);
			}
		}
	}
	return ans;
}

int main(){
	cin >> m;
	for(ll i = 1; i <= m; i ++){
		ll s, len, numl, numr, id;
		cin >> s >> len >> numl >> numr;
		edge[s].u = s * 2 - 1;
		edge[s].v = s * 2;
		edge[s].w = len;
		for(ll j = 1; j <= numl; j ++){
			cin >> id;
			edge[s].lside[id] = 1;
		}
		for(ll j = 1; j <= numr; j ++){
			cin >> id;
			edge[s].rside[id] = 1;
		}
	}
	for(ll i = 1; i <= 250; i ++){
		father[i] = i;
	}
	for(ll i = 1; i <= m; i ++){
		for(ll j = 1; j <= m; j ++){
			if(i == j)continue;
			if(edge[i].lside[j] && edge[j].lside[i]){
				merge(edge[i].u, edge[j].u);
			}
			if(edge[i].lside[j] && edge[j].rside[i]){
				merge(edge[i].u, edge[j].v);
			}
			if(edge[i].rside[j] && edge[j].lside[i]){
				merge(edge[i].v, edge[j].u);
			}
			if(edge[i].rside[j] && edge[j].rside[i]){
				merge(edge[i].v, edge[j].v);
			}
		}
	}
	for(ll i = 1; i <= 2 * m; i ++){
		if(father[i] == i){
			idx[i] = ++n;
		}
	}
	for(ll i = 1; i <= m; i ++){
		edge[i].u = idx[find(edge[i].u)];
		edge[i].v = idx[find(edge[i].v)];
		adj[edge[i].u][edge[i].v] = edge[i].w;
		adj[edge[i].v][edge[i].u] = edge[i].w;
		dis[edge[i].u][edge[i].v] = edge[i].w;
		dis[edge[i].v][edge[i].u] = edge[i].w;
	}
	cout << Floyd() << "\n";
	return 0;
}
```
# 总结
Floyd 算法似乎从方方面面看都很平庸：时间复杂度高达 $\mathcal{O}(n^3)$，需要空间复杂度耗费较大的邻接矩阵存图，甚至连模板的使用环境都比较小。
然而 Floyd 算法具有较高的灵活性、可读性和可写性。一旦深刻理解了它的原理，就可以加以变通，解决许许多多看似复杂的算法。以上就是例子，希望大家不要想我最初一样，只背了模板，没有思考含义。
> Floyd 算法之所以被发明出来，并不是因为他比 Dijkstra 更快，比 SPFA 更好理解，而是因为，~~他善~~啊……

